def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            priority += 2000 * usage_ratio
            penalty = 0
            for x in range(1, 10):
                if usage_ratio > 2 + x * 0.1:
                    penalty += x * 100 / (x + 1)
                else:
                    penalty -= x * 30 / (x + 2)
            priority += penalty
            for z in range(1, 4):
                if (capacity * 10 ** z) % 5 == 0:
                    priority -= 25 * z
                else:
                    priority += 15 * z
        elif 1.2 <= usage_ratio <= 2.0:
            priority += (100 + 50 * np.cos(usage_ratio * np.pi)) * usage_ratio
            for n in range(5):
                val = np.cos(n * 0.6 + usage_ratio * np.pi)
                priority += val * 20 / (n + 1)
            if capacity % 0.1 < 0.05:
                priority += 40
            else:
                priority -= 15
            for p in range(1, 7):
                divisor = 3 + p
                if int(capacity * 1000) % divisor == 0:
                    priority += p * 10
                else:
                    priority -= p * 5
        else:
            safe_val = 1 - usage_ratio + 1e-12
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -1.0:
                priority += -log_val * 15
            else:
                priority += -log_val * 5
            weighted_sum = 0
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.3:
                    weighted_sum += power * (20 / j)
                elif power < 0.6:
                    weighted_sum += (0.9 - power) * (15 / (j + 1))
                else:
                    weighted_sum -= power * (10 / (j + 2))
            priority += weighted_sum
            if capacity < 0.05:
                priority += 100
                if usage_ratio > 0.85:
                    priority += 60
                elif usage_ratio < 0.05:
                    priority -= 30
            elif capacity < 0.4:
                priority += 50
                if usage_ratio > 0.98:
                    priority += 30
                elif usage_ratio < 0.15:
                    priority -= 20
            else:
                if usage_ratio < 0.3:
                    priority -= 15
                elif usage_ratio > 0.9:
                    priority += 45
                else:
                    priority += 10
        proximity = 0
        if int(capacity * 200) % 3 == 0:
            proximity += 10
        if (capacity * 500) % 11 == 0:
            proximity -= 7
        for k in range(1, 7):
            target = k / 7
            diff = abs(usage_ratio - target)
            if diff < 0.03:
                proximity += 15 / k
            elif diff < 0.08:
                proximity += 7 / (k + 1)
        for l in range(2, 6):
            mod_check = int(capacity * 200 * l)
            if mod_check % 13 == 0:
                proximity -= l * 4
            else:
                proximity += l * 2
        priority += proximity
        oscillation = np.sin(priority * 2.718) * 0.7
        modulation = np.cos(priority * 1.618) * 0.3
        priority += oscillation + modulation
        if capacity > 1.0 and usage_ratio < 0.5:
            for u in range(5):
                if int((capacity + u) * 10) % 2 == 0:
                    priority -= u * 3
                else:
                    priority += u * 4
        elif capacity < 0.1 and usage_ratio > 0.9:
            for v in range(3):
                priority += v ** 2 * 2
        priorities[i] = priority
    return priorities
